// Binary row format serde — reads row sets from the framework, writes
// params and SQL declarations back. One generic reader, one generic writer.
// No per-type codegen. Must agree exactly with protocol.zig and storage.zig.
//
// Hand-written SDK runtime. Will be generated by codegen once the binary
// protocol is stable.

// --- Constants (match protocol.zig) ---

export const columns_max = 32;
export const column_name_max = 128;
export const cell_value_max = 4096;

// --- Type tags (match protocol.zig TypeTag) ---

export const TypeTag = {
  integer: 0x01,
  float: 0x02,
  text: 0x03,
  blob: 0x04,
  null: 0x05,
} as const;

export const QueryMode = {
  one: 0x00,
  all: 0x01,
} as const;

export const MessageTag = {
  route_request: 0x01,
  route_prefetch_response: 0x02,
  prefetch_results: 0x03,
  handle_render_response: 0x04,
  render_results: 0x05,
  html_response: 0x06,
} as const;

// --- Row set reader (framework → sidecar) ---

const _decoder = new TextDecoder();

export interface ColumnInfo {
  typeTag: number;
  name: string;
}

export interface RowSet {
  columns: ColumnInfo[];
  rows: Record<string, unknown>[];
}

/**
 * Read a self-describing row set from a binary buffer.
 * Returns the parsed row set and the byte offset after the last row.
 *
 * Wire format:
 *   [u16 BE col_count]
 *   [columns: col_count x { u8 type_tag, u16 BE name_len, name_bytes }]
 *   [u32 BE row_count]
 *   [rows: row_count x { values: col_count x typed_value }]
 */
export function readRowSet(buf: DataView, offset: number): { result: RowSet; offset: number } {
  let pos = offset;

  // Column count — defense-in-depth: framework is trusted but validate anyway.
  const colCount = buf.getUint16(pos, false);
  pos += 2;
  if (colCount > columns_max) throw new Error("column count exceeds max: " + colCount);

  // Column descriptors.
  const columns: ColumnInfo[] = [];
  for (let i = 0; i < colCount; i++) {
    const typeTag = buf.getUint8(pos);
    pos += 1;
    const nameLen = buf.getUint16(pos, false);
    pos += 2;
    if (nameLen > column_name_max) throw new Error("column name exceeds max: " + nameLen);
    const name = _decoder.decode(new Uint8Array(buf.buffer, buf.byteOffset + pos, nameLen));
    pos += nameLen;
    columns.push({ typeTag, name });
  }

  // Row count.
  const rowCount = buf.getUint32(pos, false);
  pos += 4;

  // Rows.
  const rows: Record<string, unknown>[] = [];
  for (let r = 0; r < rowCount; r++) {
    const row: Record<string, unknown> = {};
    for (const col of columns) {
      let value: unknown;
      [value, pos] = readTypedValue(buf, pos, col.typeTag);
      row[col.name] = value;
    }
    rows.push(row);
  }

  return { result: { columns, rows }, offset: pos };
}

/**
 * Read a single typed value from the buffer.
 * Returns [value, newOffset].
 */
function readTypedValue(buf: DataView, pos: number, typeTag: number): [unknown, number] {
  switch (typeTag) {
    case TypeTag.integer: {
      // i64 little-endian. JS numbers are f64 — safe up to 2^53.
      // For values > 2^53, use BigInt. For now, read as Number.
      const lo = buf.getUint32(pos, true);
      const hi = buf.getInt32(pos + 4, true);
      pos += 8;
      return [hi * 0x100000000 + lo, pos];
    }
    case TypeTag.float: {
      const val = buf.getFloat64(pos, true);
      pos += 8;
      return [val, pos];
    }
    case TypeTag.text: {
      const len = buf.getUint16(pos, false);
      pos += 2;
      if (len > cell_value_max) throw new Error("text value exceeds max: " + len);
      const val = _decoder.decode(new Uint8Array(buf.buffer, buf.byteOffset + pos, len));
      pos += len;
      return [val, pos];
    }
    case TypeTag.blob: {
      const len = buf.getUint16(pos, false);
      pos += 2;
      if (len > cell_value_max) throw new Error("blob value exceeds max: " + len);
      const val = new Uint8Array(buf.buffer, buf.byteOffset + pos, len).slice();
      pos += len;
      return [val, pos];
    }
    case TypeTag.null:
      return [null, pos];
    default:
      throw new Error("unknown type tag: " + typeTag);
  }
}

// --- Param writer (sidecar → framework) ---

const _encoder = new TextEncoder();

/**
 * Write a parameter list into a binary buffer.
 * Returns the number of bytes written.
 *
 * Wire format:
 *   [params: count x { u8 type_tag, typed_value }]
 *
 * The param count is written separately by the caller (it's part of
 * the SQL declaration format, not the param format itself).
 */
export function writeParams(buf: DataView, offset: number, params: unknown[]): number {
  let pos = offset;
  for (const param of params) {
    pos = writeTypedParam(buf, pos, param);
  }
  return pos - offset;
}

const I64_MAX = 2n ** 63n - 1n;
const I64_MIN = -(2n ** 63n);

/**
 * Write a single typed parameter value.
 * JS type → wire type mapping:
 *   number → integer (if safe integer) or float
 *   string → text (length must fit u16)
 *   boolean → integer (0 or 1)
 *   Uint8Array → blob (length must fit u16)
 *   null/undefined → null
 *   bigint → integer (must fit i64)
 */
function writeTypedParam(buf: DataView, pos: number, val: unknown): number {
  if (val === null || val === undefined) {
    buf.setUint8(pos, TypeTag.null);
    return pos + 1;
  }

  if (typeof val === "boolean") {
    buf.setUint8(pos, TypeTag.integer);
    pos += 1;
    buf.setInt32(pos, val ? 1 : 0, true);
    buf.setInt32(pos + 4, 0, true);
    return pos + 8;
  }

  if (typeof val === "number") {
    if (Number.isInteger(val) && Math.abs(val) <= Number.MAX_SAFE_INTEGER) {
      buf.setUint8(pos, TypeTag.integer);
      pos += 1;
      const lo = val & 0xFFFFFFFF;
      const hi = Math.floor(val / 0x100000000);
      buf.setUint32(pos, lo >>> 0, true);
      buf.setInt32(pos + 4, hi, true);
      return pos + 8;
    } else {
      buf.setUint8(pos, TypeTag.float);
      pos += 1;
      buf.setFloat64(pos, val, true);
      return pos + 8;
    }
  }

  if (typeof val === "bigint") {
    if (val > I64_MAX || val < I64_MIN) {
      throw new Error("bigint param exceeds i64 range: " + val);
    }
    buf.setUint8(pos, TypeTag.integer);
    pos += 1;
    buf.setBigInt64(pos, val, true);
    return pos + 8;
  }

  if (typeof val === "string") {
    buf.setUint8(pos, TypeTag.text);
    pos += 1;
    const encoded = _encoder.encode(val);
    if (encoded.length > 0xFFFF) {
      throw new Error("text param exceeds u16 max length: " + encoded.length);
    }
    buf.setUint16(pos, encoded.length, false);
    pos += 2;
    new Uint8Array(buf.buffer, buf.byteOffset + pos, encoded.length).set(encoded);
    return pos + encoded.length;
  }

  if (val instanceof Uint8Array) {
    buf.setUint8(pos, TypeTag.blob);
    pos += 1;
    if (val.length > 0xFFFF) {
      throw new Error("blob param exceeds u16 max length: " + val.length);
    }
    buf.setUint16(pos, val.length, false);
    pos += 2;
    new Uint8Array(buf.buffer, buf.byteOffset + pos, val.length).set(val);
    return pos + val.length;
  }

  throw new Error("unsupported param type: " + typeof val);
}

// --- SQL declaration writer (sidecar → framework) ---

export interface SqlDeclaration {
  key: string;
  sql: string;
  mode: "one" | "all";
  params: unknown[];
}

/**
 * Write SQL declarations (prefetch or render queries) into a binary buffer.
 * Returns the number of bytes written.
 *
 * Wire format:
 *   [u8 query_count]
 *   [queries: query_count x {
 *       u8 key_len, key_bytes,
 *       u16 sql_len, sql_bytes,
 *       u8 mode,
 *       u8 param_count,
 *       params: param_count x { u8 type_tag, typed_value }
 *   }]
 */
export function writeSqlDeclarations(buf: DataView, offset: number, declarations: SqlDeclaration[]): number {
  let pos = offset;

  // Query count.
  buf.setUint8(pos, declarations.length);
  pos += 1;

  for (const decl of declarations) {
    // Key — u8 length.
    const keyBytes = _encoder.encode(decl.key);
    if (keyBytes.length > 0xFF) {
      throw new Error("declaration key exceeds u8 max length: " + decl.key);
    }
    buf.setUint8(pos, keyBytes.length);
    pos += 1;
    new Uint8Array(buf.buffer, buf.byteOffset + pos, keyBytes.length).set(keyBytes);
    pos += keyBytes.length;

    // SQL — u16 length.
    const sqlBytes = _encoder.encode(decl.sql);
    if (sqlBytes.length > 0xFFFF) {
      throw new Error("declaration SQL exceeds u16 max length: " + sqlBytes.length);
    }
    buf.setUint16(pos, sqlBytes.length, false);
    pos += 2;
    new Uint8Array(buf.buffer, buf.byteOffset + pos, sqlBytes.length).set(sqlBytes);
    pos += sqlBytes.length;

    // Mode.
    buf.setUint8(pos, decl.mode === "all" ? QueryMode.all : QueryMode.one);
    pos += 1;

    // Params — u8 count.
    if (decl.params.length > 0xFF) {
      throw new Error("declaration params exceed u8 max count: " + decl.params.length);
    }
    buf.setUint8(pos, decl.params.length);
    pos += 1;
    const bytesWritten = writeParams(buf, pos, decl.params);
    pos += bytesWritten;
  }

  return pos - offset;
}

// --- Write queue serializer (handle writes → framework) ---

export interface WriteEntry {
  sql: string;
  params: unknown[];
}

/**
 * Write a handle's write queue into a binary buffer.
 * Returns the number of bytes written.
 *
 * Wire format:
 *   [u8 write_count]
 *   [writes: write_count x {
 *       u16 sql_len, sql_bytes,
 *       u8 param_count,
 *       params: param_count x { u8 type_tag, typed_value }
 *   }]
 */
export function writeWriteQueue(buf: DataView, offset: number, writes: WriteEntry[]): number {
  let pos = offset;

  buf.setUint8(pos, writes.length);
  pos += 1;

  for (const entry of writes) {
    // SQL — u16 length.
    const sqlBytes = _encoder.encode(entry.sql);
    if (sqlBytes.length > 0xFFFF) {
      throw new Error("write SQL exceeds u16 max length: " + sqlBytes.length);
    }
    buf.setUint16(pos, sqlBytes.length, false);
    pos += 2;
    new Uint8Array(buf.buffer, buf.byteOffset + pos, sqlBytes.length).set(sqlBytes);
    pos += sqlBytes.length;

    // Params — u8 count.
    if (entry.params.length > 0xFF) {
      throw new Error("write params exceed u8 max count: " + entry.params.length);
    }
    buf.setUint8(pos, entry.params.length);
    pos += 1;
    const bytesWritten = writeParams(buf, pos, entry.params);
    pos += bytesWritten;
  }

  return pos - offset;
}

// --- Frame IO helpers ---

/**
 * Read a frame header (4-byte BE length) and return the payload length.
 * Returns -1 if the buffer doesn't have enough bytes for the header.
 */
export function readFrameLength(buf: DataView, offset: number): number {
  if (buf.byteLength - offset < 4) return -1;
  return buf.getUint32(offset, false);
}

/**
 * Write a frame header (4-byte BE length) at the given position.
 */
export function writeFrameHeader(buf: DataView, offset: number, payloadLength: number): void {
  buf.setUint32(offset, payloadLength, false);
}
